// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.packed;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;

import java.lang.reflect.Field;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class PackedPlanRecipeTest {

	@Test
	void extractsOnlySelectedPhysicalDagAndPreservesSharedChildren() {
		PackedQuery query = query();
		PackedMemo memo = new PackedMemo(query, 16, 4, 4, 4, 4, 8);
		int rootLogical = query.rootRelId();
		int rootGroup = memo.logicalGroupId(rootLogical);
		int leafGroup = query.relChild(rootLogical, 0);
		int any = memo.anyPropertyId();
		int[] none = new int[0];

		int leafPhysical = memo.addPhysicalAlternative(leafGroup, 301, 11, any, 7, none, 0, 0);
		int leafWinner = memo.offerWinner(leafGroup, any, 0, 0, 0, leafPhysical, 1.0d, 1.0d, 1.0d, none, 0,
				0);
		int[] repeatedLeafGroups = { leafGroup, leafGroup };
		int rootPhysical = memo.addPhysicalAlternative(rootGroup, 302, 12, any, 8, repeatedLeafGroups, 0, 2);
		int[] repeatedLeafWinners = { leafWinner, leafWinner };
		int rootWinner = memo.offerWinner(rootGroup, any, 0, 0, 0, rootPhysical, 2.0d, 3.0d, 3.0d,
				repeatedLeafWinners, 0, 2);

		PackedPlanRecipe recipe = memo.extractPlanRecipe(rootWinner);

		assertEquals(2, recipe.size());
		assertEquals(2, recipe.rootRecipeId());
		assertEquals(301, recipe.operatorTag(1));
		assertEquals(302, recipe.operatorTag(2));
		assertEquals(12, recipe.payloadId(2));
		assertEquals(any, recipe.deliveredPropertyId(2));
		assertEquals(8, recipe.implementationForm(2));
		assertEquals(2, recipe.childCount(2));
		assertEquals(1, recipe.childRecipeId(2, 0));
		assertEquals(1, recipe.childRecipeId(2, 1));
	}

	@Test
	void recipeHotStateContainsOnlyPrimitiveArraysAndScalars() {
		for (Field field : PackedPlanRecipe.class.getDeclaredFields()) {
			assertFalse(TupleExpr.class.isAssignableFrom(field.getType()), field.getName());
			assertFalse(java.util.Collection.class.isAssignableFrom(field.getType()), field.getName());
			assertFalse(java.util.Map.class.isAssignableFrom(field.getType()), field.getName());
		}
	}

	private static PackedQuery query() {
		SimpleValueFactory valueFactory = SimpleValueFactory.getInstance();
		StatementPattern left = new StatementPattern(Var.of("person"),
				Var.of("namePredicate", valueFactory.createIRI("urn:name")), Var.of("name"));
		StatementPattern right = new StatementPattern(Var.of("person"),
				Var.of("agePredicate", valueFactory.createIRI("urn:age")), Var.of("age"));
		return PackedQueryCodec.encode(new Join(left, right));
	}
}
